                'book_num': book_num,
                'book_id': book['book_id'],
                'title': book['title'],
                'categories': categories,
                'details': book['details']
            })
    except:
        # Skip if parsing fails
        continue

# Process 5-star ratings - extract numeric part from purchase_id
five_star_ids = []
for rating in five_star_ratings:
    try:
        pur_num = int(rating['purchase_id'].split('_')[1])
        five_star_ids.append({
            'pur_num': pur_num,
            'purchase_id': rating['purchase_id'],
            'avg_rating': float(rating['avg_rating']),
            'rating_count': int(rating['rating_count'])
        })
    except:
        continue

# Find matches based on numeric ID
matches = []
five_star_dict = {item['pur_num']: item for item in five_star_ids}

for book in lit_fiction_ids:
    if book['book_num'] in five_star_dict:
        rating_info = five_star_dict[book['book_num']]
        matches.append({
            'title': book['title'],
            'book_id': book['book_id'],
            'purchase_id': rating_info['purchase_id'],
